# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
import pandas as pd

app = Flask(__name__)
labels_data = []  # This will act as the database for this example

@app.route('/submit_label', methods=['POST'])
def submit_label():
    data = request.get_json()
    labels_data.append(data)
    return jsonify({'status': 'OK'}), 201

@app.route('/aggregate_labels', methods=['GET'])
def aggregate_labels():
    df = pd.DataFrame(labels_data)
    # Majority voting
    mode_df = df.mode()
    result = {}
    for col in df.columns:
        if mode_df[col][0] is not None:
            result[col] = mode_df[col][0]
    return jsonify(result)

if __name__ == '__main__':
    app.run()